const body = $input.first().json.body;
const entry = body && body.entry && body.entry[0];
const change = entry && entry.changes && entry.changes[0];
const value = change && change.value;
const message = value && value.messages && value.messages[0];

if (!message) {
  return [{ json: { hasMessage: false } }];
}

const phone = message.from;
const phoneNumberId = value.metadata && value.metadata.phone_number_id;
const text = message.type === 'text' ? message.text.body : '[unsupported message type]';

const staticData = $getWorkflowStaticData('global');
if (!staticData.conversations) staticData.conversations = {};
const state = staticData.conversations[phone] || {
  date: null, time: null, time_range: null,
  name: null, email: null, status: 'new', history: []
};

const systemPrompt = `You are a friendly WhatsApp appointment booking assistant.
Guide users through booking appointments naturally, one question at a time.
Understand natural language dates/times; convert dates to YYYY-MM-DD and times to 24h HH:MM.
Never ask for info already known (see state below).
If date or time is missing, ask for it.
Once date and time are known, set action "CHECK_CALENDAR" so availability can be checked.
Once slot is confirmed and name is missing, ask for full name, action "REPLY".
Once name known and email missing, ask for email, action "REPLY".
Once name, email, date and time are all known, set action "CREATE_EVENT".
Never mention APIs, Google Calendar, n8n, or internal systems.

Respond ONLY with valid JSON, no extra text:
{
  "action": "REPLY" | "CHECK_CALENDAR" | "CREATE_EVENT",
  "reply": "message to send, or null if action needs a backend result first",
  "date": "YYYY-MM-DD or null",
  "time": "HH:MM or null",
  "time_range": "morning|afternoon|evening or null",
  "name": "string or null",
  "email": "string or null"
}`;

const messages = [
  { role: 'system', content: systemPrompt },
  { role: 'system', content: `Known state so far: ${JSON.stringify(state)}` },
  ...(state.history || []),
  { role: 'user', content: text }
];

return [{ json: { hasMessage: true, phone, phoneNumberId, text, state, ollamaMessages: messages } }];

let content = ($json.message && $json.message.content) || '{}';
let parsed;
try { parsed = JSON.parse(content); }
catch (e) { parsed = { action: 'REPLY', reply: "Sorry, could you rephrase that?" }; }

const prev = $('Prepare Message and State').first().json;
const state = prev.state;

if (parsed.date) state.date = parsed.date;
if (parsed.time) state.time = parsed.time;
if (parsed.time_range) state.time_range = parsed.time_range;
if (parsed.name) state.name = parsed.name;
if (parsed.email) state.email = parsed.email;

const day = state.date || new Date(Date.now() + 86400000).toISOString().slice(0, 10);

return [{
  json: {
    ...prev,
    action: parsed.action,
    aiReply: parsed.reply,
    state,
    day,
    timeMin: `${day}T00:00:00`,
    timeMax: `${day}T23:59:59`
  }
}];

const ctx = $('Parse AI and Set Query Range').first().json;
const state = ctx.state;
const day = ctx.day;
const events = $input.all().map(i => i.json).filter(e => e.start);

const workStart = 9, workEnd = 17, slotMin = 30;
let slots = [];
for (let h = workStart; h < workEnd; h++) {
  for (let m = 0; m < 60; m += slotMin) {
    const start = new Date(`${day}T${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}:00`);
    const end = new Date(start.getTime() + slotMin * 60000);
    const overlaps = events.some(e => {
      const bs = new Date(e.start.dateTime || e.start.date);
      const be = new Date(e.end.dateTime || e.end.date);
      return start < be && end > bs;
    });
    if (!overlaps) slots.push(`${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`);
  }
}

const range = state.time_range;
if (range === 'morning') slots = slots.filter(s => s < '12:00');
if (range === 'afternoon') slots = slots.filter(s => s >= '12:00' && s < '17:00');
if (range === 'evening') slots = slots.filter(s => s >= '17:00');

const requestedSlotFree = state.time ? slots.includes(state.time) : false;
const readyToBook = ctx.action === 'CREATE_EVENT' && state.name && state.email && state.date && state.time && requestedSlotFree;

let finalReply;
if (readyToBook) {
  finalReply = null; // will be set after booking
} else if (ctx.action === 'CHECK_CALENDAR' || (state.time && !requestedSlotFree)) {
  const top3 = slots.slice(0, 3);
  finalReply = top3.length
    ? `Here are the available times:\n\n${top3.map(s => `• ${s}`).join('\n')}\n\nWhich works best for you?`
    : `Sorry, nothing is free then. Could you try another day?`;
} else {
  finalReply = ctx.aiReply || 'Could you tell me more?';
}

let eventStart = null, eventEnd = null;
if (readyToBook) {
  eventStart = `${state.date}T${state.time}:00`;
  const endDate = new Date(new Date(eventStart).getTime() + 30 * 60000);
  const pad = n => String(n).padStart(2, '0');
  eventEnd = `${state.date}T${pad(endDate.getHours())}:${pad(endDate.getMinutes())}:00`;
}

return [{
  json: {
    ...ctx,
    readyToBook,
    finalReply,
    eventStart,
    eventEnd,
    eventSummary: `Appointment - ${state.name || ''}`
  }
}];

