const staticData = $getWorkflowStaticData('global');
const state = $json.state;
let finalReply = $json.finalReply;

if ($json.readyToBook) {
  finalReply = `You're all set! Your appointment is confirmed for ${state.date} at ${state.time}. I've also sent a confirmation email to ${state.email}.`;
}

state.history = state.history || [];
state.history.push({ role: 'user', content: $json.text });
state.history.push({ role: 'assistant', content: finalReply });
if (state.history.length > 20) state.history = state.history.slice(-20);
staticData.conversations[$json.phone] = state;

return [{ json: { ...$json, finalReply } }];
